mapper.insert:
INSERT INTO EMPLOYEE_INFO (
    USER_ID
    , DEPT_CD
    , JBGR_CD
    , JOIN_YMD
    , RETMT_YMD
    , EMPL_STAT_CD
    , ATCH_FILE_ID
    , CHRG_DUTY_CN
    , RGTR_ID
    , LAST_MDFR_ID
    , REG_DT
    , MDFCN_DT
    , EMPL_TYPE_CD
    , CTRCT_END_YMD
) VALUES (
    #{userId, jdbcType=VARCHAR}
    , #{deptCd, jdbcType=CHAR}
    , #{jbgrCd, jdbcType=CHAR}
    , #{joinYmd, jdbcType=DATE}
    , #{retmtYmd, jdbcType=DATE}
    , '01'
    , #{atchFileId, jdbcType=VARCHAR}
    , #{chrgDutyCn, jdbcType=VARCHAR}
    , #{rgtrId, jdbcType=VARCHAR}
    , #{lastMdfrId, jdbcType=VARCHAR}
    , SYSTIMESTAMP
    , SYSTIMESTAMP
    , #{emplTypeCd, jdbcType=CHAR}



            , TO_DATE(SUBSTR(#{ctrctEndYmd, jdbcType=VARCHAR}, 1, 10), 'YYYY-MM-DD')


            , NULL


)

mapper.select:
SELECT /* MEMBER 테이블 (M_ 접두사) */ m.USER_ID AS M_USER_ID, m.USER_ENPSWD AS M_USER_ENPSWD, m.USER_NAME AS M_USER_NAME, m.USER_ENRRNO AS M_USER_ENRRNO, m.USER_GNDR_CD AS M_USER_GNDR_CD, m.USER_BRDT AS M_USER_BRDT, m.JOIN_DT AS M_JOIN_DT, m.USER_TELNO AS M_USER_TELNO, m.USER_EMAIL_ADDR AS M_USER_EMAIL_ADDR, m.USER_ZIP AS M_USER_ZIP, m.USER_ADDR AS M_USER_ADDR, m.USER_DADDR AS M_USER_DADDR, m.USER_PROFILE AS M_USER_PROFILE, m.REG_DATE AS M_REG_DATE, m.MOD_DATE AS M_MOD_DATE, m.ENABLE AS M_ENABLE, m.USER_ROLE AS M_USER_ROLE,
ei.DEPT_CD, ei.EMPL_STAT_CD, ei.EMPL_TYPE_CD,
/* EMPLOYEE_INFO 테이블 (EI_ 접두사 및 매핑 컬럼) */ ei.USER_ID AS EI_USER_ID, ei.DEPT_CD AS EI_DEPT_CD, ei.JBGR_CD AS EI_JBGR_CD, ei.JOIN_YMD AS EI_JOIN_YMD, ei.RETMT_YMD AS EI_RETMT_YMD, ei.EMPL_STAT_CD AS EI_EMPL_STAT_CD, ei.ATCH_FILE_ID AS EI_ATCH_FILE_ID, ei.CHRG_DUTY_CN AS EI_CHRG_DUTY_CN, ei.EMPL_TYPE_CD AS EI_EMPL_TYPE_CD, ei.CTRCT_END_YMD AS EI_CTRCT_END_YMD, ei.MNT_USER_ID AS EI_MNT_USER_ID,
/* DEPARTMENT 테이블 */ d.DEPT_NM,
/* 직급명 */ j.JBGR_NM,
/* 재직/휴직: 현재 급여(USE_YN='Y'), 퇴사자: 마지막으로 받은 급여 */ es.BASE_SALARY FROM MEMBER m LEFT JOIN EMPLOYEE_INFO ei ON m.USER_ID = ei.USER_ID LEFT JOIN DEPARTMENT d ON ei.DEPT_CD = d.DEPT_CD LEFT JOIN JOB_GRADE j ON ei.JBGR_CD = j.JBGR_CD LEFT JOIN EMPLOYEE_SALARY es ON m.USER_ID = es.USER_ID AND ( (NVL(ei.EMPL_STAT_CD, '01') != '03' AND es.USE_YN = 'Y') OR (ei.EMPL_STAT_CD = '03' AND es.APPLY_YMD = ( SELECT MAX(APPLY_YMD) FROM EMPLOYEE_SALARY WHERE USER_ID = m.USER_ID )) ) WHERE m.USER_ROLE = 'ROLE_ADMIN' ORDER BY m.USER_ID

SELECT m.USER_ID AS M_USER_ID, m.USER_ENPSWD AS M_USER_ENPSWD, m.USER_NAME AS M_USER_NAME, m.USER_ENRRNO AS M_USER_ENRRNO, m.USER_GNDR_CD AS M_USER_GNDR_CD, m.USER_BRDT AS M_USER_BRDT, m.JOIN_DT AS M_JOIN_DT, m.USER_TELNO AS M_USER_TELNO, m.USER_EMAIL_ADDR AS M_USER_EMAIL_ADDR, m.USER_ZIP AS M_USER_ZIP, m.USER_ADDR AS M_USER_ADDR, m.USER_DADDR AS M_USER_DADDR, m.USER_PROFILE AS M_USER_PROFILE, m.REG_DATE AS M_REG_DATE, m.MOD_DATE AS M_MOD_DATE, m.ENABLE AS M_ENABLE, m.USER_ROLE AS M_USER_ROLE, ei.DEPT_CD, ei.EMPL_STAT_CD, ei.EMPL_TYPE_CD, ei.USER_ID AS EI_USER_ID, ei.DEPT_CD AS EI_DEPT_CD, ei.JBGR_CD AS EI_JBGR_CD, ei.JOIN_YMD AS EI_JOIN_YMD, ei.RETMT_YMD AS EI_RETMT_YMD, ei.EMPL_STAT_CD AS EI_EMPL_STAT_CD, ei.ATCH_FILE_ID AS EI_ATCH_FILE_ID, ei.CHRG_DUTY_CN AS EI_CHRG_DUTY_CN, ei.EMPL_TYPE_CD AS EI_EMPL_TYPE_CD, ei.CTRCT_END_YMD AS EI_CTRCT_END_YMD, d.DEPT_NM, j.JBGR_NM, es.BASE_SALARY FROM MEMBER m LEFT JOIN EMPLOYEE_INFO ei ON m.USER_ID = ei.USER_ID LEFT JOIN DEPARTMENT d ON ei.DEPT_CD = d.DEPT_CD LEFT JOIN JOB_GRADE j ON ei.JBGR_CD = j.JBGR_CD LEFT JOIN EMPLOYEE_SALARY es ON m.USER_ID = es.USER_ID AND ( (NVL(ei.EMPL_STAT_CD, '01') != '03' AND es.USE_YN = 'Y') OR (ei.EMPL_STAT_CD = '03' AND es.APPLY_YMD = ( SELECT MAX(APPLY_YMD) FROM EMPLOYEE_SALARY WHERE USER_ID = m.USER_ID )) ) WHERE m.USER_ROLE = 'ROLE_ADMIN'
AND m.USER_NAME LIKE '%' || #{detailCondition.keyword} || '%'
AND TO_CHAR(ei.JOIN_YMD, 'YYYY') = #{detailCondition.year}
AND ei.EMPL_STAT_CD = #{detailCondition.status}
AND ei.DEPT_CD = #{detailCondition.deptCd}
AND ei.JBGR_CD = #{detailCondition.jbgrCd}
AND ei.EMPL_TYPE_CD = #{detailCondition.emplTypeCd}
ORDER BY
m.USER_NAME d.DEPT_NM j.JBGR_NM ei.JOIN_YMD ei.EMPL_TYPE_CD ei.EMPL_STAT_CD ei.CTRCT_END_YMD m.USER_ID
DESC ASC
NULLS LAST OFFSET #{offset} ROWS FETCH NEXT #{screenSize} ROWS ONLY

SELECT COUNT(*)
FROM MEMBER m
LEFT JOIN EMPLOYEE_INFO ei ON m.USER_ID = ei.USER_ID
WHERE m.USER_ROLE = 'ROLE_ADMIN'

    AND m.USER_NAME LIKE '%' || #{detailCondition.keyword} || '%'


    AND TO_CHAR(ei.JOIN_YMD, 'YYYY') = #{detailCondition.year}


    AND ei.EMPL_STAT_CD = #{detailCondition.status}


    AND ei.DEPT_CD = #{detailCondition.deptCd}


    AND ei.JBGR_CD = #{detailCondition.jbgrCd}


    AND ei.EMPL_TYPE_CD = #{detailCondition.emplTypeCd}

SELECT m.USER_ID, m.USER_ENPSWD, m.USER_NAME, m.USER_ENRRNO, m.USER_GNDR_CD, m.USER_BRDT, m.JOIN_DT, m.USER_TELNO, m.USER_EMAIL_ADDR, m.USER_ZIP, m.USER_ADDR, m.USER_DADDR, m.USER_PROFILE, m.REG_DATE, m.MOD_DATE, m.ENABLE, m.USER_ROLE, (SELECT COUNT(*) FROM CLASSROOM_MEMBER cm WHERE cm.USER_ID = m.USER_ID) AS CLASS_CNT, (SELECT mi.USER_NAME FROM CLASSROOM_MEMBER cm JOIN CLASSROOM cl ON cm.CLASS_SN = cl.CLASS_SN JOIN MEMBER mi ON cl.OPNR_USER_ID = mi.USER_ID WHERE cm.USER_ID = m.USER_ID AND ROWNUM = 1) AS FIRST_INSTR_NM, (SELECT cl.CLASS_NM FROM CLASSROOM_MEMBER cm JOIN CLASSROOM cl ON cm.CLASS_SN = cl.CLASS_SN WHERE cm.USER_ID = m.USER_ID AND ROWNUM = 1) AS FIRST_CLASS_NM FROM MEMBER m WHERE m.USER_ROLE IN ('ROLE_USER', 'ROLE_STUDENT')
AND m.USER_NAME LIKE '%' || #{detailCondition.keyword} || '%'
AND TO_CHAR(m.JOIN_DT, 'YYYY') = #{detailCondition.year}
AND m.USER_ROLE = 'ROLE_STUDENT' AND NOT EXISTS (SELECT 1 FROM CLASSROOM_MEMBER cm WHERE cm.USER_ID = m.USER_ID)
AND m.USER_ROLE = #{detailCondition.userRole}
AND m.ENABLE = #{detailCondition.enable}
ORDER BY
m.USER_NAME m.USER_ROLE m.ENABLE m.JOIN_DT m.USER_ID
DESC ASC
NULLS LAST OFFSET #{offset} ROWS FETCH NEXT #{screenSize} ROWS ONLY

SELECT COUNT(*)
FROM MEMBER m
WHERE m.USER_ROLE IN ('ROLE_USER', 'ROLE_STUDENT')

    AND m.USER_NAME LIKE '%' || #{detailCondition.keyword} || '%'


    AND TO_CHAR(m.JOIN_DT, 'YYYY') = #{detailCondition.year}


    AND m.USER_ROLE = 'ROLE_STUDENT'
    AND NOT EXISTS (SELECT 1 FROM CLASSROOM_MEMBER cm WHERE cm.USER_ID = m.USER_ID)


    AND m.USER_ROLE = #{detailCondition.userRole}


    AND m.ENABLE = #{detailCondition.enable}

SELECT COUNT(*) FROM MEMBER m LEFT JOIN EMPLOYEE_INFO ei ON m.USER_ID = ei.USER_ID LEFT JOIN JOB_GRADE j ON ei.JBGR_CD = j.JBGR_CD WHERE m.USER_ROLE = 'ROLE_ADMIN' AND m.ENABLE = 'Y'
AND m.USER_NAME LIKE '%' || #{detailCondition.keyword} || '%'
AND ei.DEPT_CD = #{detailCondition.deptCd}
AND TRIM(j.JBGR_NM) = #{detailCondition.jbgrNm}
AND EXISTS (SELECT 1 FROM ADMINLOGIN_LOG l WHERE l.USER_ID = m.USER_ID AND l.LOGOUT_DT IS NULL)
AND NOT EXISTS (SELECT 1 FROM ADMINLOGIN_LOG l WHERE l.USER_ID = m.USER_ID AND l.LOGOUT_DT IS NULL)

SELECT JBGR_CD, JBGR_NM, DEPT_CD, SORT_ORD, USE_YN, BASE_ANN_LV_DAYS
FROM JOB_GRADE

AND DEPT_CD = #{deptCd}
AND USE_YN  = #{useYn}

ORDER BY SORT_ORD NULLS LAST, JBGR_CD
OFFSET #{offset} ROWS FETCH NEXT #{size} ROWS ONLY

SELECT COUNT(*) FROM JOB_GRADE

AND DEPT_CD = #{deptCd}
AND USE_YN  = #{useYn}

SELECT h.ANN_LV_SN AS annLvSn, h.ANN_USER_ID AS annUserId, TRIM(h.ANN_TYPE_CD) AS annTypeCd, h.ANN_STRT_YMD AS annStrtYmd, h.ANN_END_YMD AS annEndYmd, h.ANN_REQ_DAYS AS annReqDays, h.ANN_RSN_CN AS annRsnCn, h.APRVL_DOC_SN AS aprvlDocSn, h.REG_DT AS regDt, m.USER_NAME AS userName, d.DEPT_NM AS deptNm, j.JBGR_NM AS jbgrNm, c.COM_CD_NM AS annTypeNm FROM ANNUAL_LEAVE_HISTORY h JOIN MEMBER m ON h.ANN_USER_ID = m.USER_ID LEFT JOIN EMPLOYEE_INFO ei ON m.USER_ID = ei.USER_ID LEFT JOIN DEPARTMENT d ON ei.DEPT_CD = d.DEPT_CD LEFT JOIN JOB_GRADE j ON ei.JBGR_CD = j.JBGR_CD LEFT JOIN COM_CD c ON TRIM(c.CL_CODE) = '221' AND TRIM(c.COM_CD) = TRIM(h.ANN_TYPE_CD)
AND m.USER_NAME LIKE '%' || #{detailCondition.keyword} || '%'
AND TRIM(h.ANN_TYPE_CD) = #{detailCondition.type}
AND SUBSTR(h.ANN_STRT_YMD, 1, 4) = #{detailCondition.year}
AND SUBSTR(h.ANN_STRT_YMD, 1, 6) = #{detailCondition.month}
AND ei.DEPT_CD = #{detailCondition.deptCd}
ORDER BY
m.USER_NAME d.DEPT_NM h.ANN_TYPE_CD h.ANN_REQ_DAYS h.ANN_STRT_YMD
ASC DESC
NULLS LAST OFFSET #{offset} ROWS FETCH NEXT #{screenSize} ROWS ONLY

SELECT COUNT(*)
FROM ANNUAL_LEAVE_HISTORY h
JOIN MEMBER m            ON h.ANN_USER_ID = m.USER_ID
LEFT JOIN EMPLOYEE_INFO ei ON m.USER_ID = ei.USER_ID


        AND m.USER_NAME LIKE '%' || #{detailCondition.keyword} || '%'


        AND TRIM(h.ANN_TYPE_CD) = #{detailCondition.type}


        AND SUBSTR(h.ANN_STRT_YMD, 1, 4) = #{detailCondition.year}


        AND SUBSTR(h.ANN_STRT_YMD, 1, 6) = #{detailCondition.month}


        AND ei.DEPT_CD = #{detailCondition.deptCd}

SELECT COUNT(*) FROM MEMBER m JOIN EMPLOYEE_INFO ei ON m.USER_ID = ei.USER_ID WHERE m.USER_ROLE = 'ROLE_ADMIN' AND NVL(ei.EMPL_STAT_CD, '01') != '03'
AND ei.DEPT_CD = #{detailCondition.deptCd}
AND m.USER_NAME LIKE '%' || #{detailCondition.keyword} || '%'
